import "./progress.css";

import { Progress } from "radix-ui";
import { cn } from "tailwind-variants";

import { progressVariants } from "./progress.variants";

export type ProgressProps = React.ComponentProps<typeof Progress.Root>;

export const ProgressRoot = ({ className, value, ...props }: ProgressProps) => {
  const { indicator, root } = progressVariants();

  return (
    <Progress.Root className={cn(root(), className)} value={value} {...props}>
      <Progress.Indicator
        className={indicator()}
        style={{ transform: `translateX(-${100 - (value ?? 0)}%)` }}
      />
    </Progress.Root>
  );
};

import { tv, type VariantProps } from "tailwind-variants";

export const progressVariants = tv({
  slots: {
    indicator: "progress__indicator",
    root: "progress",
  },
});

export type ProgressVariants = VariantProps<typeof progressVariants>;

.progress {
  @apply bg-primary/20 relative h-2 w-full overflow-hidden rounded-full;
  transform: translateZ(0);
}

.progress__indicator {
  @apply bg-primary size-full transition-transform duration-500 ease-in-out;
}

import { ProgressRoot } from "./progress";

export const Progress = {
  Root: ProgressRoot,
};

export { ProgressRoot };

export type { ProgressProps } from "./progress";

export { type ProgressVariants, progressVariants } from "./progress.variants";
